{
  "chapter": {
    "description": "L'histoire de l'art ne consiste pas à mémoriser des dates ou des noms de peintres. C'est apprendre à décoder des images pour comprendre les humains qui les ont créées. Découvrez comment cette discipline aiguise votre regard sur le monde visuel et donne du sens aux objets qui nous entourent.",
    "title": "À quoi sert l'histoire de l'art"
  },
  "lessons": [
    {
      "description": "Une peinture ou une sculpture agit comme une capsule temporelle. Découvrez comment les matériaux, les couleurs et les objets représentés révèlent la politique, les croyances et l'économie d'une société.",
      "title": "Comment les images racontent l'histoire"
    },
    {
      "description": "Ce que nous trouvons magnifique aujourd'hui aurait pu sembler choquant ou laid il y a quelques siècles. Voyez comment les standards esthétiques évoluent et ce qu'ils disent de nos valeurs profondes.",
      "title": "Pourquoi le concept de beauté change tout le temps"
    },
    {
      "description": "Des affiches publicitaires aux décors de films en passant par les jeux vidéo, les créateurs d'aujourd'hui recyclent constamment les techniques et les symboles classiques. Apprenez à repérer ces clins d'œil visuels autour de vous.",
      "title": "L'art du passé dans notre monde moderne"
    },
    {
      "description": "Organiser des expositions, expertiser des trouvailles, restaurer des toiles anciennes ou protéger le patrimoine en danger. Plongez dans les activités concrètes de ceux qui font vivre et transmettent l'histoire de l'art.",
      "title": "Les métiers et projets autour des œuvres d'art"
    }
  ]
}
